1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const INSURANCE_VALUES: Record<string, number> = {
20	  sword: 1000,
21	  amulet: 600,
22	  staff: 800,
23	  potion: 400,
24	  rune: 250,
25	  moonstone: 250,
26	};
27	
28	const DEDUCTIBLE = 100;
29	
30	const COMPONENT_BLOCK_PREMIUM: Record<string, number> = {
31	  rune: 60,
32	  moonstone: 60,
33	};
34	
35	function calculateBasePremium(items: any[]): number {
36	  const countsByType: Record<string, number> = {};
37	  for (const item of items) {
38	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
39	  }
40	
41	  let total = 0;
42	  for (const type of Object.keys(countsByType)) {
43	    const count = countsByType[type];
44	    if (count === 3 && COMPONENT_BLOCK_PREMIUM[type] !== undefined) {
45	      total += COMPONENT_BLOCK_PREMIUM[type];
46	    } else {
47	      total += count * BASE_PREMIUMS[type];
48	    }
49	  }
50	  return total;
51	}
52	
53	function calculateItemSurcharges(items: any[]): number {
54	  let surcharges = 0;
55	  for (const item of items) {
56	    const itemBase = BASE_PREMIUMS[item.type];
57	    if (item.cursed) {
58	      surcharges += itemBase * CURSE_SURCHARGE_RATE;
59	    }
60	    if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
61	      surcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
62	    }
63	  }
64	  return surcharges;
65	}
66	
67	function calculatePremium(items: any[], customer: any, isFollowUp: boolean): number {
68	  const basePremium = calculateBasePremium(items);
69	  const itemSurcharges = calculateItemSurcharges(items);
70	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
71	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
72	  const followUpDiscount = isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
73	  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
74	}
