76	export function processScenario(scenario: any): unknown {
77	  const { customer } = scenario;
78	  const results: any[] = [];
79	  const policies: { items: any[]; insuranceSum: number; remainingCap: number }[] = [];
80	  let quotesSeen = 0;
81	  for (const step of scenario.steps) {
82	    if (step.op === "claim") {
83	      const policy = policies[step.policy];
84	      let totalPayout = 0;
85	      for (const damage of step.incident.damages) {
86	        const reimbursement = damage.amount - DEDUCTIBLE;
87	        totalPayout += reimbursement;
88	      }
89	      policy.remainingCap -= totalPayout;
90	      results.push({ payout: totalPayout, remainingCap: policy.remainingCap });
91	    } else {
92	      const isFollowUp = quotesSeen > 0;
93	      const premium = calculatePremium(step.items, customer, isFollowUp);
94	      results.push({ premium });
95	      const insuranceSum = step.items.reduce(
96	        (sum: number, item: any) => sum + INSURANCE_VALUES[item.type],
97	        0
98	      );
99	      policies.push({ items: step.items, insuranceSum, remainingCap: 2 * insuranceSum });
100	      quotesSeen++;
101	    }
102	  }
103	  return { results };
104	}
